const source = $json;

// Support both Gmail API (payload.headers array) and IMAP (headers object/array)
const getHeader = (name) => {
  // Gmail API format: payload.headers is array of {name, value}
  const gmailHeaders = source.payload?.headers;
  if (Array.isArray(gmailHeaders)) {
    return gmailHeaders.find((h) => String(h.name || '').toLowerCase() === String(name).toLowerCase())?.value || '';
  }
  // IMAP format: headers is object or plain source fields
  const headers = source.headers || {};
  return headers[name] || headers[name.toLowerCase()] || '';
};

const parseAddress = (value) => {
  const text = String(value || '').trim();
  const match = text.match(/<([^>]+)>/);
  return (match ? match[1] : text).trim();
};

const fromRaw = source.from || getHeader('From') || '';
const toRaw = source.to || getHeader('To') || '';
const subject = source.subject || getHeader('Subject') || '(No subject)';

// Extract attachments - handle both Gmail API (nested parts) and IMAP (attachments array)
const attachments = [];
const walkParts = (parts) => {
  if (!Array.isArray(parts)) return;
  for (const part of parts) {
    if (part?.filename) {
      attachments.push({
        fileName: part.filename,
        mimeType: part.mimeType || '',
        extractedText: ''
      });
    }
    if (Array.isArray(part?.parts)) walkParts(part.parts);
  }
};
walkParts(source.payload?.parts);

// IMAP may have attachments directly
if (Array.isArray(source.attachments)) {
  source.attachments.forEach((a) => {
    if (a.filename && !attachments.find((att) => att.fileName === a.filename)) {
      attachments.push({
        fileName: a.filename || '',
        mimeType: a.contentType || '',
        extractedText: ''
      });
    }
  });
}

const from = parseAddress(fromRaw);
// IMAP uses text/textPlain; Gmail uses textPlain/snippet/textHtml
const text = source.text || source.textPlain || source.snippet || source.textHtml || '';

// IMAP doesn't provide messageId reliably, use uid or generate
const messageId = source.id || source.messageId || getHeader('message-id') || source.uid || `imap-${Date.now()}`;
// IMAP doesn't have threadId like Gmail; use inReplyTo or fallback to messageId
const threadId = source.threadId || getHeader('in-reply-to') || messageId;

return [{
  json: {
    mailbox: 'lgauci@airosoftware.com',
    to: toRaw ? [toRaw] : ['lgauci@airosoftware.com'],
    from,
    subject,
    text,
    messageId,
    threadId,
    inReplyTo: getHeader('In-Reply-To') || getHeader('in-reply-to') || '',
    references: (getHeader('References') || getHeader('references') || '').split(' ').filter(Boolean),
    routingHints: [
      {
        mailboxPattern: 'lgauci@airosoftware.com',
        companyNameHint: 'Acme',
        workflowNameHint: 'IT Support'
      },
      {
        mailboxPattern: 'supplier-onboarding@example.com',
        companyNameHint: 'Supplier',
        workflowNameHint: 'Supplier Onboarding'
      }
    ],
    attachments
  }
}];

const source = $json;
const attachmentText = (source.attachments || [])
  .map((attachment) => `${attachment.fileName}: ${attachment.extractedText || ''}`.trim())
  .join('\n');

const matchedRoute = (source.routingHints || []).find((route) => route.mailboxPattern === source.mailbox) || null;

return [{
  json: {
    mailbox: source.mailbox,
    to: source.to || [],
    from: source.from,
    senderDomain: String(source.from || '').split('@')[1] || '',
    inboundEmail: {
      subject: source.subject,
      text: source.text,
      messageId: source.messageId,
      threadId: source.threadId,
      inReplyTo: source.inReplyTo,
      references: source.references || []
    },
    attachmentSummary: attachmentText,
    combinedText: [source.subject, source.text, attachmentText].filter(Boolean).join('\n\n'),
    routeHint: matchedRoute,
    linkLookup: {
      matched: false,
      workflowEntryUuid: '',
      reason: 'No persisted email-thread mapping in sample workflow'
    }
  }
}];

const source = $('Normalize Email Payload').first().json;
const companies = $input.all().map((item) => item.json);
const routeHint = source.routeHint || {};
const companyHint = String(routeHint.companyNameHint || source.senderDomain || '').toLowerCase();

const ranked = companies
  .map((company) => {
    const name = String(company.name || '').toLowerCase();
    let score = 0;

    if (companyHint && name.includes(companyHint)) score += 10;
    if (companyHint && companyHint.includes(name)) score += 6;
    if (source.senderDomain && name.includes(String(source.senderDomain).split('.')[0])) score += 4;

    return { company, score };
  })
  .sort((a, b) => b.score - a.score);

const selected = ranked[0]?.company;
if (!selected) {
  throw new Error('Could not resolve company from mailbox and email hints.');
}

return [{
  json: {
    ...source,
    company: {
      uuid: selected.uuid,
      name: selected.name,
      active: selected.active
    },
    companyCandidates: ranked.slice(0, 5).map((item) => ({
      uuid: item.company.uuid,
      name: item.company.name,
      score: item.score
    }))
  }
}];

const source = $('Resolve Company').first().json;
const workflows = $input.all().map((item) => item.json);
const body = String(source.combinedText || '').toLowerCase();
const isReply = Boolean(source.inboundEmail?.inReplyTo) || Boolean(source.linkLookup?.matched);
const workflowHint = String(source.routeHint?.workflowNameHint || '').toLowerCase();

let action = 'create_workflow';
let canSelfResolve = false;
let replyDraft = 'We have logged your issue and will keep you updated.';

if (body.includes('resolved') || body.includes('fixed') || body.includes('working now')) {
  action = 'self_resolve';
  canSelfResolve = true;
  replyDraft = 'Thanks for the update. Based on your email this looks resolved. Please let us know if the issue returns.';
} else if (isReply || body.includes('existing ticket') || body.includes('update case') || body.includes('follow up')) {
  action = 'update_workflow';
  replyDraft = 'Thanks for the additional information. We have updated your existing case.';
}

const workflowCandidates = workflows
  .map((workflow) => {
    const name = String(workflow.name || '').toLowerCase();
    let score = 0;
    if (workflowHint && name.includes(workflowHint)) score += 10;
    if (body.includes(name)) score += 6;
    if (name.includes('support') && (body.includes('issue') || body.includes('error') || body.includes('help'))) score += 3;
    return { workflow, score };
  })
  .sort((a, b) => b.score - a.score);

const selectedWorkflow = workflowCandidates[0]?.workflow || null;

return [{
  json: {
    ...source,
    availableWorkflowTypes: workflows.map((workflow) => ({
      uuid: workflow.uuid,
      name: workflow.name,
      status: workflow.status
    })),
    aiDecision: {
      summary: source.inboundEmail?.subject || 'Client support request',
      canSelfResolve,
      action,
      replyNeeded: true,
      replyDraft,
      workflowNameHint: selectedWorkflow?.name || source.routeHint?.workflowNameHint || '',
      workflowUuidCandidate: selectedWorkflow?.uuid || '',
      stepTitleHint: body.includes('printer') ? 'investigate' : '',
      existingEntryReferenceHint: '',
      entryName: source.inboundEmail?.subject || 'New support case',
      commentText: `Inbound email from ${source.from}:\n\n${source.combinedText}`
    }
  }
}];

const source = $('AI Decision Placeholder').first().json;
const workflows = $('MSFrog Get Workflow Types').all().map((item) => item.json);
const hint = String(source.aiDecision.workflowNameHint || '').toLowerCase();

const activeWorkflows = workflows.filter((workflow) => {
  const status = String(workflow.status || '').toLowerCase();
  return status === '' || status === 'active';
});

const ranked = activeWorkflows
  .map((workflow) => {
    const name = String(workflow.name || '').toLowerCase();
    let score = 0;
    if (hint && name.includes(hint)) score += 10;
    if (hint && hint.includes(name)) score += 6;
    return { workflow, score };
  })
  .sort((a, b) => b.score - a.score);

const selectedWorkflow = ranked[0]?.workflow;
if (!selectedWorkflow) {
  throw new Error('Could not resolve an active workflow type from available definitions.');
}

const steps = Array.isArray(selectedWorkflow.steps) ? selectedWorkflow.steps : [];
const stepHint = String(source.aiDecision.stepTitleHint || '').toLowerCase();
const selectedStep = steps.find((step) => String(step.title || '').toLowerCase().includes(stepHint)) || steps[0];

if (!selectedStep) {
  throw new Error('Selected workflow has no steps, so entry creation cannot continue.');
}

return [{
  json: {
    ...source,
    selectedWorkflow: {
      uuid: selectedWorkflow.uuid,
      name: selectedWorkflow.name,
      stepUuid: selectedStep.uuid,
      stepTitle: selectedStep.title
    },
    msfrogCreate: {
      workflowUuid: selectedWorkflow.uuid,
      name: source.aiDecision.entryName,
      description: `Auto-created from email ${source.inboundEmail.messageId}`,
      stepAssignments: [
        {
          workflow_step_uuid: selectedStep.uuid,
          assigned_user_uuid: null,
          due_date: null
        }
      ]
    }
  }
}];

const source = $('AI Decision Placeholder').first().json;
const createdEntry = $('MSFrog Create Workflow Entry').first().json;

return [{
  json: {
    outcome: 'created',
    workflowEntryUuid: createdEntry.uuid,
    replyTo: source.from,
    replySubject: `Re: ${source.inboundEmail.subject}`,
    replyBody: `${source.aiDecision.replyDraft}\n\nReference: ${createdEntry.entry_number || createdEntry.uuid}`,
    mappingRecord: {
      mailbox: source.mailbox,
      messageId: source.inboundEmail.messageId,
      threadId: source.inboundEmail.threadId,
      workflowEntryUuid: createdEntry.uuid,
      companyUuid: source.company.uuid,
      workflowUuid: source.selectedWorkflow?.uuid || '',
      lastAction: 'create_workflow'
    }
  }
}];

const source = $('AI Decision Placeholder').first().json;
const entries = $('MSFrog Get Existing Entries').all().map((item) => item.json);
const text = String(source.combinedText || '').toLowerCase();
const subject = String(source.inboundEmail.subject || '').toLowerCase();
const referenceHint = String(source.aiDecision.existingEntryReferenceHint || '').toLowerCase();

const ranked = entries
  .map((entry) => {
    const workflowName = String(entry.workflow?.name || entry.workflow_name || '').toLowerCase();
    const entryNumber = String(entry.entry_number || '').toLowerCase();
    const entryName = String(entry.name || entry.entry_name || '').toLowerCase();
    let score = 0;

    if (referenceHint && entryNumber.includes(referenceHint)) score += 12;
    if (subject && entryName.includes(subject)) score += 8;
    if (workflowName && text.includes(workflowName)) score += 5;
    if (source.linkLookup?.workflowEntryUuid && entry.uuid === source.linkLookup.workflowEntryUuid) score += 20;

    return { entry, score };
  })
  .sort((a, b) => b.score - a.score);

const selectedEntry = ranked[0]?.entry;
if (!selectedEntry) {
  throw new Error('Could not resolve an existing workflow entry to update.');
}

const steps = Array.isArray(selectedEntry.steps) ? selectedEntry.steps : [];
const stepHint = String(source.aiDecision.stepTitleHint || '').toLowerCase();
const selectedStep = steps.find((step) => String(step.title || '').toLowerCase().includes(stepHint))
  || steps.find((step) => String(step.status || '').toLowerCase() !== 'completed')
  || steps[0];

if (!selectedStep) {
  throw new Error('Resolved workflow entry has no steps to update.');
}

return [{
  json: {
    ...source,
    selectedEntry: {
      uuid: selectedEntry.uuid,
      entryNumber: selectedEntry.entry_number || '',
      workflowName: selectedEntry.workflow?.name || selectedEntry.workflow_name || '',
      stepUuid: selectedStep.uuid,
      stepTitle: selectedStep.title
    },
    msfrogUpdate: {
      workflowEntryUuid: selectedEntry.uuid,
      name: source.aiDecision.entryName,
      description: `Updated from reply email ${source.inboundEmail.messageId}`,
      stepAssignments: [
        {
          workflow_entry_step_uuid: selectedStep.uuid,
          assigned_user_uuid: selectedStep.assigned_user_uuid || null,
          due_date: selectedStep.due_date || null
        }
      ]
    }
  }
}];

const source = $('AI Decision Placeholder').first().json;
const updatedEntry = $('MSFrog Update Workflow Entry').first().json;

return [{
  json: {
    outcome: 'updated',
    workflowEntryUuid: updatedEntry.uuid,
    replyTo: source.from,
    replySubject: `Re: ${source.inboundEmail.subject}`,
    replyBody: `${source.aiDecision.replyDraft}\n\nReference: ${updatedEntry.entry_number || updatedEntry.uuid}`,
    mappingRecord: {
      mailbox: source.mailbox,
      messageId: source.inboundEmail.messageId,
      threadId: source.inboundEmail.threadId,
      workflowEntryUuid: updatedEntry.uuid,
      companyUuid: source.company.uuid,
      lastAction: 'update_workflow'
    }
  }
}];

const source = $('AI Decision Placeholder').first().json;

return [{
  json: {
    outcome: 'self_resolve',
    replyTo: source.from,
    replySubject: `Re: ${source.inboundEmail.subject}`,
    replyBody: source.aiDecision.replyDraft,
    mappingRecord: {
      mailbox: source.mailbox,
      messageId: source.inboundEmail.messageId,
      threadId: source.inboundEmail.threadId,
      workflowEntryUuid: source.linkLookup?.workflowEntryUuid || '',
      companyUuid: source.company.uuid,
      lastAction: 'self_resolve'
    }
  }
}];

const result = $json;
const ai = $('AI Decision Placeholder').first()?.json?.aiDecision || {};
const company = $('Resolve Company').first()?.json?.company || {};

const selectedWorkflow = $('Prepare Create Payload').first()?.json?.selectedWorkflow
  || $('Prepare Update Payload').first()?.json?.selectedEntry
  || null;

const action = String(ai.action || result.mappingRecord?.lastAction || 'unknown');
const outcome = String(result.outcome || 'unknown');
const createdOrUpdatedEntryUuid = result.workflowEntryUuid || result.mappingRecord?.workflowEntryUuid || '';

const summaryLines = [
  `Outcome: ${outcome}`,
  `Action decided: ${action}`,
  `Company: ${company.name || 'unknown'} (${company.uuid || 'n/a'})`,
  `Workflow hint: ${ai.workflowNameHint || 'n/a'}`,
  `Selected workflow/entry: ${selectedWorkflow?.name || selectedWorkflow?.workflowName || 'n/a'}`,
  `Selected step: ${selectedWorkflow?.stepTitle || 'n/a'} (${selectedWorkflow?.stepUuid || 'n/a'})`,
  `Workflow entry UUID: ${createdOrUpdatedEntryUuid || 'none'}`,
  `Mailbox: ${result.mappingRecord?.mailbox || 'n/a'}`,
  `Thread: ${result.mappingRecord?.threadId || 'n/a'}`,
  `Message ID: ${result.mappingRecord?.messageId || 'n/a'}`,
  `Reply target: ${result.replyTo || 'n/a'}`,
  `Reply subject: ${result.replySubject || 'n/a'}`
];

return [{
  json: {
    ...result,
    executionSummary: {
      outcome,
      action,
      companyName: company.name || null,
      companyUuid: company.uuid || null,
      workflowHint: ai.workflowNameHint || null,
      selectedWorkflowName: selectedWorkflow?.name || selectedWorkflow?.workflowName || null,
      selectedStepTitle: selectedWorkflow?.stepTitle || null,
      selectedStepUuid: selectedWorkflow?.stepUuid || null,
      workflowEntryUuid: createdOrUpdatedEntryUuid || null,
      mailbox: result.mappingRecord?.mailbox || null,
      threadId: result.mappingRecord?.threadId || null,
      messageId: result.mappingRecord?.messageId || null
    },
    summaryText: summaryLines.join('\n')
  }
}];

const summary = $json.executionSummary || {};
const outcome = String(summary.outcome || '').trim();
const action = String(summary.action || '').trim();

const errors = [];

if (!summary.companyUuid) errors.push('companyUuid is missing');
if (!summary.mailbox) errors.push('mailbox is missing');
// threadId and messageId are optional for IMAP email sources
if (!outcome) errors.push('outcome is missing');
if (!action) errors.push('action is missing');

if (action === 'create_workflow' || outcome === 'created') {
  if (!summary.workflowEntryUuid) errors.push('workflowEntryUuid is missing for create flow');
  if (!summary.selectedWorkflowName) errors.push('selectedWorkflowName is missing for create flow');
}

if (action === 'update_workflow' || outcome === 'updated') {
  if (!summary.workflowEntryUuid) errors.push('workflowEntryUuid is missing for update flow');
  if (!summary.selectedStepUuid) errors.push('selectedStepUuid is missing for update flow');
}

if (action === 'self_resolve' || outcome === 'self_resolve') {
  if (!$json.replyBody) errors.push('replyBody is missing for self-resolve flow');
}

if (errors.length > 0) {
  throw new Error(`Execution assertions failed: ${errors.join('; ')}`);
}

return [{
  json: {
    ...$json,
    assertions: {
      passed: true,
      checkedAt: new Date().toISOString(),
      rulesChecked: [
        'base summary fields (IMAP compatible)',
        'create/update/self_resolve-specific fields'
      ]
    }
  }
}];
